INSERT INTO articles (id, url, title, excerpt, image, published, writer, category) VALUES ('ede30a2ac68fba8152f345149a9782febe7cb0a4ee2adece510a0707665b987a', 'https://circulardesignpraxis.substack.com/p/announcement-circular-design-week', '[Announcement] Circular Design Week 2023 を開催します！/ Welcome to Circular Design Week 2023 in Kagoshima!', '2023年11月27日から12月3日までの７日間、鹿児島県の５つの地域に渡り、国内外のサーキュラーデザインの実践者や研究者とともに「土地に根ざした循環生態系の未来」を探索するツアー・カンファレンスを開催します！', 'https://substackcdn.com/image/fetch/f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F994974bd-d8de-4aa9-acfb-5551775d128a_10866x5315.jpeg', '2023-10-27T05:00:44.041000+00:00', 'Circular Design Praxis', 'クリエイティブ') ON CONFLICT(url) DO NOTHING;
INSERT INTO articles (id, url, title, excerpt, image, published, writer, category) VALUES ('924a336cc32419f5c76707a80e2cf9846a9f547009b4fd0e4da40149197e2dca', 'https://circulardesignpraxis.substack.com/p/7-study-dry-stone-walling-a-practice', '#7 [STUDY] 石積み－自然のなかに自分をはめ込む / Dry Stone Walling, a Practice in Grounding One''s Self in Nature.', '日本各地の農村における生活の風景として今も残る、石積み。東京工業大学環境・社会理工学院教授の真田純子さんは、2013年に石積み学校を立ち上げ、風景の保存や技術の継承に取り組んでいる。そんな真田さんが石積みに見る、人と自然との関係性とは。', 'https://substackcdn.com/image/fetch/f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F33f896e9-2a35-482e-9b05-6cd2e3b05d8b_4032x3024.jpeg', '2023-09-29T03:00:04.500000+00:00', 'Circular Design Praxis', 'クリエイティブ') ON CONFLICT(url) DO NOTHING;
INSERT INTO articles (id, url, title, excerpt, image, published, writer, category) VALUES ('bfc20ff5df4e35ab0ec3fb21aceadbb098163688c83664d442cc883ab3869991', 'https://circulardesignpraxis.substack.com/p/6-2-dialogue-measuring-the-un-measurable', '#6-2 [DIALOGUE] はかりがたいものをはかる、建築とマテリアルの主従逆転 / Measuring the Un-measurable and the Ends-Means Reversal of Architecture and Materials 岩元真明×水野大二郎対談 [後編]', '九州大学芸術工学研究院助教の岩元真明さんと、サーキュラーデザインプラクシス・ステアリングボードの水野大二郎さんによる対談。後編ではポップアップから近代名建築の保存問題、人新世におけるブリコラージュまでをトピックに、これからの設計方法論につい', 'https://substackcdn.com/image/fetch/f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F497eb189-b91c-4066-b1da-5a61b6956389_1680x1200.png', '2023-09-15T03:00:18.574000+00:00', 'Circular Design Praxis', 'クリエイティブ') ON CONFLICT(url) DO NOTHING;
INSERT INTO articles (id, url, title, excerpt, image, published, writer, category) VALUES ('913813d5fdc89ba2a89dce26af93e09f681f162a11aa8c1559a89d189681f66f', 'https://circulardesignpraxis.substack.com/p/6-1-dialogue-x-transitioning-from', '#6-1 [DIALOGUE] 不揃いな竹の建築から考える、量からXへの移行 / Transitioning from Quantity to X through Re-working Motley Bamboo into Architecture 岩元真明×水野大二郎対談 [前編]', '古来から身近な素材として、竹はさまざまな用途に利用されてきた。そんな竹を使った建築に取り組む、九州大学芸術工学研究院助教の岩元真明さんと、サーキュラーデザインプラクシス・ステアリングボードの水野大二郎さんによる本対談。不揃いな竹素材を皮切り', 'https://substackcdn.com/image/fetch/f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ff15edab0-d780-4ef8-8ceb-e4559688b60d_1680x1200.png', '2023-08-29T09:00:21.472000+00:00', 'Circular Design Praxis', 'クリエイティブ') ON CONFLICT(url) DO NOTHING;
INSERT INTO articles (id, url, title, excerpt, image, published, writer, category) VALUES ('8293e256af2cf9faabb7d1ad540ba2b217ec4450848bf39e99e3bceafbef0e00', 'https://circulardesignpraxis.substack.com/p/announcement-cdp-call-for-cdp-partners', '[Announcement] CDPパートナーを募集します📣/ Call for CDP Partners!', 'サーキュラーエコノミー/デザインに関心がある企業、自治体、教育研究機関、NPO、個人のデザイナーや実践者の皆さん、ともにサーキュラーデザインを通じた社会変革にチャレンジしませんか？ Are you a designer, researche', 'https://substack-post-media.s3.amazonaws.com/public/images/c290c508-7b55-4c45-81ad-f0fd3d507de7_1024x768.png', '2023-07-21T09:01:09.682000+00:00', 'Circular Design Praxis', 'クリエイティブ') ON CONFLICT(url) DO NOTHING;
INSERT INTO articles (id, url, title, excerpt, image, published, writer, category) VALUES ('822292bacbde79f7a96016497bdd815956077853c696f1735e513d28126cfdbb', 'https://circulardesignpraxis.substack.com/p/5-study-design-when-everybody-joins', '#5 [STUDY] 長縄跳びとデザインの力 / Design, When Everybody Joins the Long Jump Rope', '地球規模の課題に、地域で取り組むことの意味とは何なのか。第53次南極地域観測隊への参加を経て、現在は硫黄島に移住し、リトリートや気候変動対策・SDGsに関わるさまざまな実践を行う株式会社musuhi CPO（Chief Planetary ', 'https://substackcdn.com/image/fetch/f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F01a7fd3d-f1f0-4c45-8129-6865ebe3aca8_1600x1010.jpeg', '2023-07-03T09:30:41.363000+00:00', 'Circular Design Praxis', 'クリエイティブ') ON CONFLICT(url) DO NOTHING;
