INSERT INTO articles (id, url, title, excerpt, image, published, writer, category) VALUES ('1d859fbdcb9406f57992f9ddedb9df08288a9a3ba9903b905d02ed8641f84b2b', 'https://circulardesignpraxis.substack.com/p/4-study-community-networks-a-place', '#4 [STUDY] Community Networks: A Place-Based Approach for Sustainability/ インドネシアの「竹の電波塔」に見る、土着のインフラデザイン', '現代に欠かせないインフラとなったインターネット。その普及を支える電波塔を、竹でつくるまちがインドネシアにある──。ジャカルタ南東の都市バンドンを拠点とする、アート・カルチャー・メディアのプラットフォームCommon Roomの創業者グスタフ', 'https://substackcdn.com/image/fetch/$s_!t0or!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F3ed4c16b-20b7-462a-a4e6-a76d79d5961d_4032x3024.jpeg', '2023-05-31T09:00:31.587000+00:00', 'Circular Design Praxis', 'クリエイティブ') ON CONFLICT(url) DO NOTHING;
INSERT INTO articles (id, url, title, excerpt, image, published, writer, category) VALUES ('6d4874e81a0085b7a3ef17db9a6f5d6f752053ffb85981ed390704acb48c82bc', 'https://circulardesignpraxis.substack.com/p/study-travelling-light-on-circularity', '#3 [STUDY] サーキュラーを軽やかに乗りこなす/ Travelling Light on Circularity', 'ものづくりに関わる分野でありながら、サステナビリティからは少し遠い分野のようにも感じるグラフィックデザイン。ひとりのデザイナーとして、どのように持続可能性に向き合ったらいいのだろうか。ペーパーパレード代表の守田篤史さんが身近な実践から考える', 'https://substackcdn.com/image/fetch/$s_!eEAe!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F056526da-30e9-4f03-b4e6-d838011eb203_1080x601.jpeg', '2023-04-29T00:01:03.662000+00:00', 'Circular Design Praxis', 'クリエイティブ') ON CONFLICT(url) DO NOTHING;
